// Préparer les données du webhook
const body = $input.first().json.body;
const contact = body.contact || {};
const company = body.company || {};

// Séparer prénom / nom
const nameParts = (contact.name || '').trim().split(/\s+/);
const lastname = nameParts.pop() || '';
const firstname = nameParts.join(' ') || '';

// Mapper le statut vers la valeur enum HubSpot
const statusMap = {
  'Message vocal laissé': 'message_vocal_laisse',
  'Email envoyé': 'email_envoye',
  'Injoignable': 'injoignable',
  'Rendez-vous pris': 'rendez_vous_pris',
  'Ne plus rappeler': 'ne_plus_rappeler',
  'Déjà appelé': 'deja_appele',
  'Pas intéressé': 'pas_interesse',
  'Déjà en partenariat': 'deja_en_partenariat',
  'A raccroché': 'a_raccroche'
};

// Mapping statut → pipeline stage ID
const stageMap = {
  'Message vocal laissé': '4978411760',
  'Email envoyé': '4978411760',
  'Injoignable': '4978411760',
  'Rendez-vous pris': '4978411762',
  'Ne plus rappeler': '4978411766',
  'Déjà appelé': '4978411761',
  'Pas intéressé': '4978411766',
  'Déjà en partenariat': '4978411766',
  'A raccroché': '4978411760'
};

// Générer dynamiquement la valeur enum du commercial (snake_case normalisé)
function toSnakeCase(name) {
  return (name || '').trim().toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
}

return [{
  json: {
    contact_firstname: firstname,
    contact_lastname: lastname,
    contact_email: contact.email || '',
    contact_phone: contact.phone || '',
    contact_position: contact.position || '',
    contact_title_tag: contact.title_tag || '',
    contact_linkedin: contact.linkedin_url || '',
    contact_address: contact.address || '',
    notes: body.notes || '',
    company_name: company.name || '',
    company_address: company.address || '',
    company_phone: company.phone || '',
    company_website: company.website || '',
    siren: company.siren || '',
    siret: company.siret || '',
    type_entreprise: company.type_entreprise || '',
    effectif: company.effectif || '',
    chiffre_affaires: company.chiffre_affaires || '',
    capital_social: company.capital_social || '',
    forme_juridique: company.forme_juridique || '',
    numero_tva: company.numero_tva || '',
    convention_collective: company.convention_collective || '',
    status_raw: body.status || '',
    status_enum: statusMap[body.status] || body.status || '',
    pipeline_stage_id: stageMap[body.status] || '4978411759',
    commercial_raw: body.commercial || '',
    commercial_enum: toSnakeCase(body.commercial),
    source_url: body.source_url || '',
    timestamp: body.timestamp || new Date().toISOString(),
    decidento_contact_id: body.decidento_contact_id || '',
    rdv_date: body.rdv_date || '',
    send_confirmation_email: body.send_confirmation_email || false,
    send_offer_email: body.send_offer_email || false
  }
}];

// Résoudre le owner ID dynamiquement depuis la liste des owners HubSpot
const data = $('Préparer les données').first().json;
const ownersResponse = $('Chercher owners HubSpot').first().json;
const owners = (ownersResponse.body && ownersResponse.body.results) || [];
const commercialName = data.commercial_raw || '';

// Chercher le owner par nom (prénom + nom)
let ownerId = '';
if (commercialName) {
  const normalizedSearch = commercialName.toLowerCase().trim();
  const match = owners.find(o => {
    const fullName = ((o.firstName || '') + ' ' + (o.lastName || '')).toLowerCase().trim();
    return fullName === normalizedSearch;
  });
  if (match) {
    ownerId = match.id || '';
  }
}

return [{
  json: {
    ...data,
    owner_id: ownerId
  }
}];

