const data = $('Résoudre owner ID').first().json;

let companyId = '';
try { companyId = $('ID entreprise existante').first().json.company_id; } catch(e) {}
if (!companyId) {
  try { companyId = $('ID nouvelle entreprise').first().json.company_id; } catch(e) {}
}

return [{ json: { ...data, company_id: companyId } }];

// Récupérer le contact_id quel que soit le chemin (update ou create)
const data = $('Fusionner company_id').first().json;

let contactId = '';
let action = '';
try {
  contactId = $('Mettre à jour contact').first().json.body.id;
  action = 'updated';
} catch(e) {}
if (!contactId) {
